sql:
SELECT COUNT(*) 
FROM actors 
WHERE agent_id IN (SELECT agent_id FROM agents WHERE commission_rate > 0.15);

SELECT COUNT(*) AS total_movies, SUM(box_office) AS total_revenue_generated
FROM movies
WHERE runtime > 120;

SELECT COUNT(DISTINCT actor_id) AS unique_actors_count
FROM actor_roles
WHERE movie_id = 1;

SELECT M.title
FROM movies M
WHERE M.budget = (SELECT MAX(budget) FROM movies);
